import sys
from collections import deque

def can_transform(x, y):
    def reverse_and_add_bit(num, bit):
        binary = bin(num)[2:]
        binary = binary + str(bit)
        reversed_binary = binary[::-1]
        return int(reversed_binary, 2)

    if x == y:
        return True

    visited = set()
    queue = deque([x])
    visited.add(x)

    while queue:
        current = queue.popleft()
        for bit in (0, 1):
            next_val = reverse_and_add_bit(current, bit)
            if next_val == y:
                return True
            if next_val not in visited and next_val <= 10**18 * 2:
                visited.add(next_val)
                queue.append(next_val)

    return False

line = input().split()
x, y = int(line[0]), int(line[1])

if can_transform(x, y):
    print("YES")
else:
    print("NO")

